package com.mengwei.localgrowth.asset;
import com.mengwei.localgrowth.identity.AuthService.Identity;import com.mengwei.localgrowth.shared.TenantAccess;import java.util.*;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import org.springframework.web.multipart.MultipartFile;
@RestController @RequestMapping("/api/v1/assets") public class AssetController {private final AssetService service;private final TenantAccess access;public AssetController(AssetService s,TenantAccess a){service=s;access=a;}private Identity i(String h){return access.identity(h);}@PostMapping(consumes=MediaType.MULTIPART_FORM_DATA_VALUE)public Map<String,Object> upload(@RequestHeader("Authorization")String h,@RequestPart("file")MultipartFile file){return service.upload(i(h),file);}@GetMapping("/{id}")public Map<String,Object> asset(@RequestHeader("Authorization")String h,@PathVariable UUID id){return service.asset(i(h),id);}@GetMapping("/{id}/content")public ResponseEntity<byte[]> content(@RequestHeader("Authorization")String h,@PathVariable UUID id){Map<String,Object> asset=service.metadata(i(h),id);return ResponseEntity.ok().contentType(MediaType.parseMediaType(String.valueOf(asset.get("mimeType")))).header(HttpHeaders.CONTENT_DISPOSITION,"inline; filename="+asset.get("originalFilename")).body(service.bytes(i(h),id));}}
